describe("chatStore — updateAttachment", () => {
  it("marks a flow attachment as applied", () => {
    const msg = chatStore.addAssistantMessage("your flow", [
      makeFlowAttachment(false),
    ]);
    chatStore.updateAttachment(msg.id, "flow", { applied: true });

    const found = chatStore.messages.find((m) => m.id === msg.id);
    const flowAttachment = found?.attachments?.find(
      (a): a is FlowAttachment => a.kind === "flow",
    );
    expect(flowAttachment?.applied).toBe(true);
  });

  it("only updates the attachment matching the given kind", () => {
    const attachments: MessageAttachment[] = [
      makeFlowAttachment(false),
      makeSearchAttachment(),
    ];
    const msg = chatStore.addAssistantMessage("mixed", attachments);
    chatStore.updateAttachment(msg.id, "flow", { applied: true });

    const found = chatStore.messages.find((m) => m.id === msg.id);
    const searchAttachment = found?.attachments?.find(
      (a): a is SearchResultAttachment => a.kind === "search-result",
    );
    // Search attachment must be unmodified
    expect(searchAttachment?.query).toBe("drones");

    const flowAttachment = found?.attachments?.find(
      (a): a is FlowAttachment => a.kind === "flow",
    );
    expect(flowAttachment?.applied).toBe(true);
  });

  it("does not affect other messages", () => {
    const msg1 = chatStore.addAssistantMessage("flow 1", [
      makeFlowAttachment(false),
    ]);
    const msg2 = chatStore.addAssistantMessage("flow 2", [
      makeFlowAttachment(false),
    ]);
    chatStore.updateAttachment(msg1.id, "flow", { applied: true });

    const found2 = chatStore.messages.find((m) => m.id === msg2.id);
    const attachment2 = found2?.attachments?.find(
      (a): a is FlowAttachment => a.kind === "flow",
    );
    expect(attachment2?.applied).toBeFalsy();
  });

  it("is a no-op for unknown message ids", () => {
    chatStore.addAssistantMessage("msg", [makeFlowAttachment()]);
    expect(() =>
      chatStore.updateAttachment("nonexistent-id", "flow", { applied: true }),
    ).not.toThrow();
  });

  it("is a no-op when no attachment of that kind exists on the message", () => {
    const msg = chatStore.addAssistantMessage("msg", [makeSearchAttachment()]);
    expect(() =>
      chatStore.updateAttachment(msg.id, "flow", { applied: true }),
    ).not.toThrow();
    // Search attachment remains unchanged
    const found = chatStore.messages.find((m) => m.id === msg.id);
    expect(found?.attachments?.[0].kind).toBe("search-result");
  });

  it("can update multiple fields of an attachment at once", () => {
    const msg = chatStore.addAssistantMessage("msg", [
      makeFlowAttachment(false),
    ]);
    chatStore.updateAttachment(msg.id, "flow", {
      applied: true,
      validationResult: { valid: false, errors: ["missing output"] },
    });

    const found = chatStore.messages.find((m) => m.id === msg.id);
    const flowAttachment = found?.attachments?.find(
      (a): a is FlowAttachment => a.kind === "flow",
    );
    expect(flowAttachment?.applied).toBe(true);
    expect(flowAttachment?.validationResult).toMatchObject({ valid: false });
  });
});

